import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X } from 'lucide-react';

function Navbar() {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };

    window.addEventListener('scroll', handleScroll);
    setIsScrolled(window.scrollY > 50);

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Close menu when route changes
  useEffect(() => {
    setIsMenuOpen(false);
  }, [location.pathname]);

  const toggleMenu = () => {
    setIsMenuOpen(!isMenuOpen);
  };

  const closeMenu = () => {
    setIsMenuOpen(false);
  };

  return (
    <nav className={`navbar ${isScrolled ? 'scrolled' : ''}`}>
      <div className="navbar-logo">
        <Link to="/" onClick={closeMenu}>
          <img src="https://res.cloudinary.com/dppos5kvq/image/upload/v1772211773/rno1_logo_transparent_sbq7tr.png" alt="Adveria Logo" />
        </Link>
      </div>

      <div className="navbar-menu">
        <div className="hidden md:flex items-center gap-10 text-[15px] font-saans font-medium text-white/90">
          <div className="relative group">
            <Link className={`hover:text-white transition-colors py-4 inline-block ${location.pathname === '/services' ? 'text-white' : ''}`} to="/services">
              Services
            </Link>
          </div>
          <div className="relative group">
            <span className="cursor-pointer hover:text-white transition-colors py-4 inline-block">Industries</span>
          </div>
          <div className="relative group">
            <Link className={`hover:text-white transition-colors py-4 inline-block ${location.pathname === '/work' ? 'text-white' : ''}`} to="/work">
              Work
            </Link>
          </div>
          <div className="relative group">
            <Link className={`hover:text-white transition-colors py-4 inline-block ${location.pathname === '/about' ? 'text-white' : ''}`} to="/about">
              About
            </Link>
          </div>
          <div className="relative group">
            <Link className={`hover:text-white transition-colors py-4 inline-block ${location.pathname === '/blog' ? 'text-white' : ''}`} to="/blog">
              Blog
            </Link>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <Link className="hidden sm:flex items-center justify-center bg-[#E31837] px-7 py-3 rounded-[14px] text-[15px] md:text-[16px] font-saans font-medium tracking-wide text-white hover:bg-[#C8102E] hover:-translate-y-0.5 transition-all duration-300" to="/connect">
            Book a Strategy Call
          </Link>
          <button className="md:hidden p-2 text-white bg-white/10 rounded-full hover:bg-white/20 transition-colors" aria-label="Toggle Menu" onClick={toggleMenu}>
            {isMenuOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden navbar-menu ${isMenuOpen ? 'open' : ''}`}>
        <div className="flex flex-col gap-1.5">
          <Link className="hover:text-white transition-colors py-3 inline-block" to="/services" onClick={closeMenu}>
            Services
          </Link>
          <Link className="hover:text-white transition-colors py-3 inline-block" to="/work" onClick={closeMenu}>
            Work
          </Link>
          <Link className="hover:text-white transition-colors py-3 inline-block" to="/about" onClick={closeMenu}>
            About
          </Link>
          <Link className="hover:text-white transition-colors py-3 inline-block" to="/blog" onClick={closeMenu}>
            Blog
          </Link>
          <Link className="hover:text-white transition-colors py-3 inline-block text-[#A855F7]" to="/connect" onClick={closeMenu}>
            Book a Strategy Call
          </Link>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
